 18→// ── Cluster mode: fork one worker per CPU core ──
 19→// Set CLUSTER_ENABLED=true in production to use all CPU cores.
 20→// Disabled by default so local dev / single-core hosts work without surprises.
 21→const CLUSTER_ENABLED = process.env.CLUSTER_ENABLED === 'true';
 22→const WORKER_COUNT = parseInt(process.env.WORKER_COUNT, 10) || os.cpus().length;
