 38→const __filename = fileURLToPath(import.meta.url);
 39→const __dirname = dirname(__filename);
 40→const FONT_DIR = join(__dirname, '.fonts');
 41→const FONT_PATH = join(FONT_DIR, 'DejaVuSans.ttf');
 42→const FONT_BOLD_PATH = join(FONT_DIR, 'DejaVuSans-Bold.ttf');
 43→let fontsReady = false;
 44→
 45→async function ensureShareFonts() {
 46→    if (fontsReady) return;
 47→    try {
 48→        if (!existsSync(FONT_DIR)) mkdirSync(FONT_DIR, { recursive: true });
 49→
 50→        const downloads = [];
 51→        if (!existsSync(FONT_PATH)) {
 52→            downloads.push(
 53→                fetch('https://cdn.jsdelivr.net/npm/@vintproykt/dejavu-fonts-ttf@2.37.0/ttf/DejaVuSans.ttf')
 54→                    .then(r => { if (!r.ok) throw new Error(`Font fetch failed: ${r.status}`); return r.arrayBuffer(); })
 55→                    .then(buf => writeFileSync(FONT_PATH, Buffer.from(buf)))
 56→            );
 57→        }
 58→        if (!existsSync(FONT_BOLD_PATH)) {
 59→            downloads.push(
 60→                fetch('https://cdn.jsdelivr.net/npm/@vintproykt/dejavu-fonts-ttf@2.37.0/ttf/DejaVuSans-Bold.ttf')
 61→                    .then(r => { if (!r.ok) throw new Error(`Bold font fetch failed: ${r.status}`); return r.arrayBuffer(); })
 62→                    .then(buf => writeFileSync(FONT_BOLD_PATH, Buffer.from(buf)))
 63→            );
 64→        }
 65→        if (downloads.length) await Promise.all(downloads);
 66→
 67→        fontsReady = true;
 68→        console.log('Share fonts ready:', FONT_DIR);
 69→    } catch (err) {
 70→        console.error('Failed to setup share fonts:', err?.message || err);
 71→    }
 72→}
